public class RankBST {

    static class Node {
        int val; Node left, right;
        Node(int v) { val = v; }
    }

    public Node insert(Node root, int val) {
        if (root == null) return new Node(val);
        if (val < root.val) root.left = insert(root.left, val);
        else if (val > root.val) root.right = insert(root.right, val);
        return root;
    }

    public int rank(Node root, int val) {
        // Count of elements <= val in the BST
        if (root == null) return 0;
        if (val < root.val) return rank(root.left, val);
        if (val == root.val) return sizeOf(root.left) + 1;
        return sizeOf(root.left) + 1 + rank(root.right, val);
    }

    private int sizeOf(Node node) {
        if (node == null) return 0;
        return 1 + sizeOf(node.left) + sizeOf(node.right);
    }

